import {
  createBrowserRouter,
  Outlet,
  redirect,
  RouterProvider,
} from "react-router-dom";

import { useEffect, useState } from "react";
import Layout from "./components/Layout/Layout";
import ServerNav from "./components/ServerNav/ServerNav";
import Sidebar from "./components/Sidebar/Sidebar";
import Chat from "./pages/DM/Chat";
import Login from "./pages/Auth/Login";
import Register from "./pages/Auth/Register";
import Loading from "./pages/LoadingScreen/Loading";

function App() {
  const [token, setToken] = useState(null);
  const [isAuth, setIsAuth] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    setIsLoading(true);
    const token = localStorage.getItem("token");
    const expiryDate = localStorage.getItem("expiryDate");

    if (!token || !expiryDate) {
      // setIsLoading(false);
      return;
    }

    if (expiryDate) {
    }

    setToken(token);
    setIsAuth(true);

    const fetchData = async () => {
      try {
        const response = await fetch("/channels/direct-messages", {
          headers: {
            Authorization: "Bearer " + token,
          },
        });
        const messagesList = await response.json();

        await new Promise((r) => setTimeout(r, 2000));
      } catch (err) {
        console.log(err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  const logoutHandler = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("expiryDate");
    setToken(null);
    setIsAuth(false);
  };

  if (isLoading) {
    return <Loading></Loading>;
  }

  console.log(isAuth);

  let router = createBrowserRouter([
    {
      path: "/register",
      element: <Register />,
    },
    {
      path: "/login",
      element: <Login />,
    },
    {
      path: "/",
      loader: () => {
        return redirect("/login");
      },
      element: <Chat></Chat>,
    },
  ]);

  if (isAuth) {
    router = createBrowserRouter([
      {
        path: "/",
        element: (
          <Layout
            nav={isAuth && <ServerNav token={token} />}
            sidebar={isAuth && <Sidebar token={token} />}
          >
            <Outlet></Outlet>
          </Layout>
        ),
        children: [
          {
            path: "/register",
            loader: () => {
              return redirect("/");
            },
            element: <Register />,
          },
          {
            path: "/login",
            loader: () => {
              return redirect("/");
            },
            element: <Login />,
          },
          {
            path: "/",
            element: <Chat></Chat>,
          },
          {
            path: "/friends",
            element: <Chat></Chat>,
          },
        ],
      },
    ]);
  }
  return <RouterProvider router={router}></RouterProvider>;
}

export default App;
